mapper.sql:
WHERE i.company_id = #{companyId}

  AND EXISTS (
      SELECT 1
      FROM tb_stock_movement_unit mu2
      INNER JOIN tb_stock_movement m2
          ON m2.movement_id = mu2.movement_id
      WHERE mu2.unit_id = i.unit_id
        AND m2.company_id = i.company_id
        AND m2.document_id = #{documentId}
        AND m2.movement_type = 'INBOUND'
        AND m2.canceled_movement_id IS NULL
  )


  AND i.unit_id = #{unitId}


  AND u.part_id = #{partId}


  AND i.inspection_type = #{inspectionType}


  AND i.result = #{result}


  AND i.grade = #{grade}


  AND i.inspected_at >= #{dateFrom}


  AND i.inspected_at < #{dateTo}


  AND (
      u.internal_serial_no LIKE CONCAT('%', #{keyword}, '%')
      OR p.part_name LIKE CONCAT('%', #{keyword}, '%')
      OR p.model_name LIKE CONCAT('%', #{keyword}, '%')
      OR p.part_code LIKE CONCAT('%', #{keyword}, '%')
      OR EXISTS (
          SELECT 1
          FROM tb_stock_movement_unit muk
          INNER JOIN tb_stock_movement mk
              ON mk.movement_id = muk.movement_id
          INNER JOIN tb_stock_document dk
              ON dk.company_id = mk.company_id
             AND dk.document_id = mk.document_id
          WHERE muk.unit_id = i.unit_id
            AND mk.company_id = i.company_id
            AND mk.movement_type = 'INBOUND'
            AND mk.canceled_movement_id IS NULL
            AND dk.document_no LIKE CONCAT('%', #{keyword}, '%')
      )
  )

